@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})



export class AppComponent {
  name = "Teksti muuttuu";


}
<h1>Data Binding, My Dream App!</h1>
<input type="text" [(ngModel)]="name">
<p>{{ name }}</p>
